const uint16_t* getSidebarIconBitmap(int tabIndex, bool active, int size) {
  if (tabIndex < 0 || tabIndex > 6) tabIndex = 0;
  if (!active) return SIDEBAR_ICONS_IDLE[tabIndex];
  if (size <= SIDEBAR_ICON_STEP1) return SIDEBAR_ICONS_ACTIVE_28[tabIndex];
  if (size <= SIDEBAR_ICON_STEP2) return SIDEBAR_ICONS_ACTIVE_30[tabIndex];
  if (size <= SIDEBAR_ICON_STEP3) return SIDEBAR_ICONS_ACTIVE_32[tabIndex];
  if (size <= SIDEBAR_ICON_STEP4) return SIDEBAR_ICONS_ACTIVE_34[tabIndex];
  return SIDEBAR_ICONS_ACTIVE_36[tabIndex];
}
